// Merge webhook and manual trigger data into consistent format
let items = [];

try {
  // From webhook trigger (single contact)
  const webhookData = $('Webhook Trigger').first().json;
  if (webhookData && webhookData.body) {
    items.push({
      json: {
        notion_page_id: webhookData.body.notion_page_id,
        full_name: webhookData.body.full_name,
        linkedin_url: webhookData.body.linkedin_url,
        company: webhookData.body.company || '',
        title: webhookData.body.title || ''
      }
    });
  }
} catch(e) {}

try {
  // From manual trigger (batch from Notion query)
  const notionResults = $('Get Unresearched Contacts').first().json.results || [];
  for (const page of notionResults) {
    const props = page.properties;
    const name = props['Name']?.title?.[0]?.text?.content || '';
    const linkedinUrl = props['LinkedIn Profile']?.url || '';
    const company = props['Company']?.rich_text?.[0]?.text?.content || '';
    const title = props['Title']?.rich_text?.[0]?.text?.content || '';
    items.push({
      json: {
        notion_page_id: page.id,
        full_name: name,
        linkedin_url: linkedinUrl,
        company: company,
        title: title
      }
    });
  }
} catch(e) {}

return items;

// Merge Apify + Apollo data and compute priority score
const lead = $('Loop Over Contacts').first().json;

// Apify data
let apifyData = {};
try {
  const raw = $('Apify LinkedIn Scraper').first().json;
  apifyData = {
    headline: raw.headline || '',
    fullName: raw.fullName || lead.full_name,
    companyName: raw.experiences?.[0]?.companyName || lead.company,
    companyTitle: raw.experiences?.[0]?.title || lead.title,
    jobDescription: raw.experiences?.[0]?.jobDescription || '',
    profilePicture: raw.profilePicture || '',
    location: raw.location || ''
  };
} catch(e) {
  apifyData = { headline: '', fullName: lead.full_name, companyName: lead.company, companyTitle: lead.title };
}

// Apollo data
let apolloData = { employeeCount: 0, revenue: 0, revenueStr: '', industry: '', website: '', foundedYear: 0, seniority: '' };
try {
  const apollo = $('Apollo Enrichment').first().json;
  const person = apollo.person || {};
  const org = person.organization || {};
  apolloData.employeeCount = org.estimated_num_employees || org.employee_count || 0;
  const rawRev = org.annual_revenue || org.estimated_annual_revenue || 0;
  apolloData.revenue = typeof rawRev === 'string' ? parseInt(rawRev.replace(/[^0-9]/g, ''), 10) || 0 : Number(rawRev) || 0;
  apolloData.revenueStr = org.annual_revenue_printed || (apolloData.revenue ? '$' + (apolloData.revenue / 1000000).toFixed(1) + 'M' : 'Unknown');
  apolloData.industry = org.industry || '';
  apolloData.website = org.website_url || org.primary_domain || '';
  apolloData.foundedYear = org.founded_year || 0;
  apolloData.seniority = person.seniority || '';
} catch(e) {}

// Priority Scoring (max 20) — aligned with WF0_Lead_Scoring
let score = 0;
let breakdown = [];
const apolloFailed = !apolloData.employeeCount && !apolloData.revenue && !apolloData.industry;
if (apolloFailed) { breakdown.push('Apollo enrichment failed'); }

// 1. Employee Count (0-5) — compressed ICP range
if (apolloData.employeeCount >= 50 && apolloData.employeeCount <= 200) { score += 5; breakdown.push('Emp 50-200: +5'); }
else if (apolloData.employeeCount >= 20 && apolloData.employeeCount < 50) { score += 4; breakdown.push('Emp 20-49: +4'); }
else if (apolloData.employeeCount >= 10 && apolloData.employeeCount < 20) { score += 3; breakdown.push('Emp 10-19: +3'); }
else if (apolloData.employeeCount > 200) { score += 3; breakdown.push('Emp 200+: +3'); }
else if (apolloData.employeeCount > 0) { score += 1; breakdown.push('Emp <10: +1'); }
else { breakdown.push('Emp unknown: +0'); }

// 2. Revenue (0-5) — ICP baseline for unknown
if (apolloData.revenue >= 10000000) { score += 5; breakdown.push('Rev $10M+: +5'); }
else if (apolloData.revenue >= 5000000) { score += 4; breakdown.push('Rev $5-10M: +4'); }
else if (apolloData.revenue >= 1000000) { score += 3; breakdown.push('Rev $1-5M: +3'); }
else if (apolloData.revenue > 0) { score += 1; breakdown.push('Rev <$1M: +1'); }
else if (apolloData.employeeCount >= 10) { score += 2; breakdown.push('Rev unknown (ICP baseline): +2'); }
else { breakdown.push('Rev unknown: +0'); }

// 3. Title / Seniority (0-3)
const t = (apifyData.companyTitle || '').toLowerCase();
const sen = (apolloData.seniority || '').toLowerCase();
if (t.includes('ceo') || t.includes('founder') || t.includes('owner') || sen === 'founder') { score += 3; breakdown.push('CEO/Founder/Owner: +3'); }
else if (t.includes('coo') || t.includes('president') || t.includes('vp') || t.includes('vice president') || sen === 'c_suite') { score += 2; breakdown.push('COO/President/VP: +2'); }
else if (t.includes('director') || t.includes('head of') || sen === 'director') { score += 1; breakdown.push('Director/Head: +1'); }
else if (t) { breakdown.push('Other title: +0'); }
else { breakdown.push('Title unknown: +0'); }

// 4. Industry fit (0-3) — services/ops-heavy = more automation need
const ind = apolloData.industry.toLowerCase();
const highFit = ['construction','logistics','transportation','real estate','insurance','financial services','consulting','staffing','recruiting','healthcare','home services','property management','facilities','legal','accounting','marketing','government','defense','security','protective services','cleaning','janitorial'];
const medFit = ['manufacturing','retail','e-commerce','education','technology','software','information technology','telecommunications','food','restaurant','fitness','wellness'];
if (highFit.some(i => ind.includes(i))) { score += 3; breakdown.push('High-fit industry: +3'); }
else if (medFit.some(i => ind.includes(i))) { score += 2; breakdown.push('Med-fit industry: +2'); }
else if (apolloData.industry) { score += 1; breakdown.push('Other industry: +1'); }
else { breakdown.push('Industry unknown: +0'); }

// 5. Company maturity (0-2)
const currentYear = new Date().getFullYear();
const age = apolloData.foundedYear ? currentYear - apolloData.foundedYear : 0;
if (age >= 2 && age <= 10) { score += 2; breakdown.push('Age 2-10yr (scaling): +2'); }
else if (age > 10 && age <= 25) { score += 2; breakdown.push('Age 11-25yr (automation debt): +2'); }
else if (age > 25 && age <= 40) { score += 1; breakdown.push('Age 26-40yr: +1'); }
else if (apolloData.foundedYear) { breakdown.push('Age <2yr or >40yr: +0'); }
else { score += 1; breakdown.push('Founded year unknown: +1'); }

// Tier (raised thresholds for ICP spread)
let tier = score >= 15 ? 'Tier 1' : score >= 11 ? 'Tier 2' : score >= 7 ? 'Tier 3' : 'Tier 4';

return [{
  json: {
    notion_page_id: lead.notion_page_id,
    full_name: apifyData.fullName || lead.full_name,
    linkedin_url: lead.linkedin_url,
    headline: apifyData.headline,
    company_name: apifyData.companyName,
    person_title: apifyData.companyTitle,
    job_description: apifyData.jobDescription,
    employee_count: apolloData.employeeCount,
    revenue: apolloData.revenue,
    revenue_display: apolloData.revenueStr,
    industry: apolloData.industry,
    company_website: apolloData.website,
    founded_year: apolloData.foundedYear,
    priority_score: score,
    max_score: 20,
    tier: tier,
    score_breakdown: breakdown.join(' | ')
  }
}];

